//broadcast-message.model.ts
export interface Message<T extends ActionType> {
  id: string;
  timestamp: number;
  sender: 'angular' | 'flutter';
  type: 'message' | 'action';
  content?: string;
  action?: T;
  payload?: ActionPayload<T> | object;
}

export interface ConnectionStatus {
  isConnected: boolean;
  lastError?: string;
}

export enum ActionType {
  navigate = 'navigate', //requesting navigation to route
  get_auth_tokens = 'get_auth_tokens', //flutter requesting auth tokens from angular
  update_auth_tokens = 'update_auth_tokens', //updating auth tokens in flutter with angular received auth tokens
  logout = 'logout', //logout
  profile_changed = 'profile_changed', //profile (client) changed event
  update_hash = 'update_hash',
  ready = 'ready',
  r2_token_generated = 'r2_token_generated',
  r2_token_failed = 'r2_token_failed',
  entity_updated = 'entity_updated',
}

export enum NavigationPaths {
  positions = 'positions',
  login = 'login',
  test = 'test',
  auth = 'auth',
}

/**
 * Payload for navigation actions
 */
export interface NavigatePayload {
  route: string;
  params?: Record<string, string>;
  queryParams?: Record<string, string>;
  timestamp?: number;
  updateUrlOnly?: boolean; // Add this field
}

/**
 * Payload for auth token update actions
 */
export interface AuthTokensPayload {
  accessToken: string;
  refreshToken: string;
  tokenExpiry: string;
  userSession: string;
}

/**
 * Payload for profile changed actions
 */
export interface ProfileChangedPayload {
  clientId?: string;
  id?: string;
}

/**
 * Union type of all possible action payloads
 */
export type ActionPayload<T extends ActionType> = T extends ActionType.navigate
  ? NavigatePayload
  : T extends ActionType.update_auth_tokens
    ? AuthTokensPayload
    : T extends ActionType.profile_changed
      ? ProfileChangedPayload
      : undefined;
