import { inject, Injectable, Injector } from '@angular/core';
import { LocalStorageService } from '../../shared/services/local-storage.service';
import { UserSessionService } from './user-session.service';
import { AuthTokenManagerService } from './auth-token-manager.service';
import { AdminStateService } from '../../features/administration/services/state/admin-state.service';
import { ThemeDataService } from '../../shared/services/theme-data.service';
import { ClientDataService } from '../../features/clients/services/client-data.service';
import { GridConfigRegistryService } from '../../shared/services/grid-config-registry.service';
import { BroadcastMessageService } from './message.service';

@Injectable({
  providedIn: 'root',
})
export class SessionCleanupService {
  private readonly localStorage = inject(LocalStorageService);
  private readonly authTokenManager = inject(AuthTokenManagerService);
  private readonly adminState = inject(AdminStateService);
  private readonly userSessionService = inject(UserSessionService);
  private readonly themeDataService = inject(ThemeDataService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly gridConfigRegistry = inject(GridConfigRegistryService);
  private readonly injector = inject(Injector);

  private get broadcastMessageService(): BroadcastMessageService {
    return this.injector.get(BroadcastMessageService);
  }

  /**
   * Clears all authentication and user data.
   * Use this for logout operations.
   */
  clearAllAuthData(): void {
    // Clear tokens
    this.authTokenManager.clearTokens();

    // Clear sessions
    this.userSessionService.clearAllSessions();

    // Clear admin state
    this.adminState.clearAllState();

    this.themeDataService.clearTheme();

    // Clear selected client signal (but not localStorage - that's user-scoped)
    this.clientDataService.reset();

    // Clear all registered grid configurations (filters, etc.)
    this.gridConfigRegistry.clearAll();

    // Reset broadcast message service state
    this.broadcastMessageService.reset();
  }

  /**
   * Detects and handles user mismatch scenarios.
   * Returns true if mismatch was detected and cleaned up.
   */
  detectAndHandleUserMismatch(newUserId: string): boolean {
    const hasMismatch = this.localStorage.detectUserMismatch(newUserId);

    if (hasMismatch) {
      console.warn('User mismatch detected, clearing previous user data');

      // Clear only user-scoped data (keep API tokens)
      this.localStorage.clearUserScopedData();
      this.userSessionService.clearAllSessions();

      return true;
    }

    return false;
  }

  /**
   * Records the last authenticated user.
   */
  setLastAuthenticatedUser(userId: string): void {
    this.localStorage.setLastAuthenticatedUserId(userId);
  }
}
