import { Injectable } from '@angular/core';
import { BaseGridConfiguration } from '../models/grid.model';
import { BaseTreeTableConfiguration } from '../models/tree-table.model';

type ConfigType = BaseGridConfiguration | BaseTreeTableConfiguration;

/**
 * Registry service to track active grid and tree table configurations.
 * Used to clear state (like filters) from all registered configurations upon logout.
 */
@Injectable({
  providedIn: 'root',
})
export class GridConfigRegistryService {
  private readonly registry = new Set<ConfigType>();

  /**
   * Registers a configuration instance.
   * @param config The grid or tree table configuration to register.
   */
  register(config: ConfigType): void {
    this.registry.add(config);
  }

  /**
   * Clears filters from all registered configurations.
   * Should be called during the logout process.
   */
  clearAll(): void {
    this.registry.forEach((config) => {
      if (config.clearFilters) {
        config.clearFilters();
      }
    });
    // We don't clear the registry itself because the config instances are singletons
    // and will be reused if the user logs back in without a full page reload.
  }
}
