import { Injectable, Type } from '@angular/core';
import { Observable, Subject } from 'rxjs';
import { filter, map } from 'rxjs/operators';
import { BaseEntity } from '../../../shared/models';
import { SystemHealthData } from '../models';

export interface GridItemSelectedMessage {
  item: BaseEntity;
  componentType: Type<unknown>;
}

export interface TreeItemSelectedMessage {
  item: BaseEntity;
  componentType: Type<unknown>;
}

export interface DetailsPanelClosedMessage {
  reason?: string;
}

export interface GridFilterAndSelectMessage {
  entityType: string;
  entityId: string;
  entityName: string;
  filterField?: string; // defaults to 'name'
}

export interface BroadcastMessageType {
  'grid-item-selected': GridItemSelectedMessage;
  'tree-item-selected': TreeItemSelectedMessage;
  'details-panel-closed': DetailsPanelClosedMessage;
  'view-entity-in-tree': {
    entity: BaseEntity;
  };
  'entity-updated': {
    entityType: string;
    operation?: 'create' | 'update' | 'delete';
    clientId?: string;
    [key: string]: unknown;
  };
  'grid-filter-and-select': GridFilterAndSelectMessage;
  'system-health-update': {
    data: SystemHealthData;
    timestamp: string;
  };
  'websocket-status-change': {
    connected: boolean;
    reason?: string;
  };
  'health-service-alert': {
    serviceName: string;
    severity: 'warning' | 'error' | 'critical';
    message: string;
  };
  'dashboard-refresh-requested': {
    source: string;
  };
  'real-time-metrics-update': {
    service: string;
    metrics: Record<string, number>;
  };
  // Add other message types as needed
  [key: string]: unknown;
}

@Injectable({
  providedIn: 'root',
})
export class BroadcastEventMessageService {
  private readonly messageSubject = new Subject<{
    type: keyof BroadcastMessageType;
    data: unknown;
  }>();

  /**
   * Broadcast a message to all subscribers
   * @param type The message type identifier
   * @param data The data payload
   */
  broadcast<K extends keyof BroadcastMessageType>(
    type: K,
    data: BroadcastMessageType[K],
  ): void {
    this.messageSubject.next({ type, data });
  }

  /**
   * Listen for messages of a specific type
   * @param type The message type to listen for
   * @returns An observable that emits when messages of the specified type are broadcast
   */
  on<K extends keyof BroadcastMessageType>(
    type: K,
  ): Observable<BroadcastMessageType[K]> {
    return this.messageSubject.pipe(
      filter((message) => message.type === type),
      map((message) => message.data),
    );
  }
}
