import {
  ClientListItem,
  ClientResponse,
  CompanyGroupResponse,
  DistributorResponse,
  DistributorListItem,
  VendorListItem,
  VendorResponse,
} from '../../../api';

export interface AdminTreeState {
  // Distributor-scoped data
  distributorVendors: Record<string, VendorListItem[]>; // distributorId -> vendors[]
  vendorClients: Record<string, Record<string, ClientListItem[]>>; // distributorId -> vendorId -> clients[]
  vendorGroups: Record<string, Record<string, CompanyGroupResponse[]>>; // distributorId -> vendorId -> groups[]
  groupClients: Record<
    string,
    Record<string, Record<string, ClientListItem[]>>
  >; // distributorId -> vendorId -> groupId -> clients[]

  // Distributor-scoped loading states
  loadedVendors: Record<string, Set<string>>; // distributorId -> Set<vendorId>
  loadingVendors: Record<string, Set<string>>; // distributorId -> Set<vendorId>
  failedVendors: Record<string, Set<string>>; // distributorId -> Set<vendorId>

  // Distributor-scoped expansion state
  expandedNodes: Record<string, Set<string>>; // distributorId -> Set<nodeId>
  expandedGroups: Record<string, Set<string>>; // distributorId -> Set<groupId>

  // Distributor-scoped pagination
  clientPagination: Record<string, Record<string, ClientPaginationState>>; // distributorId -> paginationKey -> state

  // Global state for current context
  selectedClient: ClientResponse | null;
  clientVendor: VendorResponse | VendorListItem | null;
  vendorDistributor: DistributorResponse | null;
  distributors: DistributorListItem[];
  initialLoading: boolean;
  expandedDistributors: Set<string>;
  userPermissionLevel: UserPermissionLevel | null;
}

export interface ClientPaginationState {
  offset: number;
  limit: number;
  total: number;
  hasMore: boolean;
  loadingMore: boolean; // To show loading indicator on the "Load More" node
}

/**
 * Enum representing the permission levels a user can have in the hierarchy
 */
export enum UserPermissionLevel {
  CLIENT_ONLY = 'client-only',
  VENDOR = 'vendor',
  DISTRIBUTOR = 'distributor',
  SUPER_ADMIN = 'super-admin',
}
